+#ifndef EVENT_IMAGE_RECONSTRUCTION_FIBAR__TIME_OFFSET_HPP_
+#define EVENT_IMAGE_RECONSTRUCTION_FIBAR__TIME_OFFSET_HPP_
+
+#include <cstdint>
+#include <iostream>
+
+namespace event_image_reconstruction_fibar
+{
+class TimeOffset
+{
+public:
+  void setAveragingConstant(double alpha)
+  {
+    alpha_ = alpha;
+    oneMinusAlpha_ = 1.0 - alpha;
+  }
+  void update(uint64_t t1, uint64_t t2)
+  {
+    const double dt =
+      static_cast<double>(static_cast<int64_t>(t1) - static_cast<int64_t>(t2));
+    if (__builtin_expect(firstTime_, false)) {
+      avgDt_ = dt;
+      firstTime_ = false;
+    } else {
+      avgDt_ = avgDt_ * oneMinusAlpha_ + alpha_ * dt;
+    }
+  }
+  int64_t getOffset() const { return static_cast<int64_t>(avgDt_); }
+  bool isValid() const { return (!firstTime_); }
+
+private:
+  double avgDt_{0};
+  double alpha_{0.01};
+  double oneMinusAlpha_{1.0 - 0.01};
+  bool firstTime_{true};
+};
+}  // namespace event_image_reconstruction_fibar
+#endif  // EVENT_IMAGE_RECONSTRUCTION_FIBAR__TIME_OFFSET_HPP_

